                            name: "Long-term (12+ months)",
                            color: "#a78bfa",
                            info: {
                                title: "Sustainability & Scale",
                                content: "Evaluate governance structure. Establish regional brand recognition. Create sustainable funding model. Develop signature programs. Build bridges to other Florida communities."
                            }
