                    ]
                }
            ]
        };

        const svg = document.getElementById('mindmap-svg');
        const container = document.getElementById('mindmap-container');
        let viewBox = { x: 0, y: 0, width: 2000, height: 1500 };
        let isDragging = false;
        let dragStart = { x: 0, y: 0 };
        let expandedNodes = new Set();

        function createMindMap() {
            svg.innerHTML = '';
            svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.width} ${viewBox.height}`);

            const centerX = viewBox.width / 2;
            const centerY = viewBox.height / 2;

            drawNode(data, centerX, centerY, 0, 0, null);
        }

        function drawNode(node, x, y, level, angle, parentPos) {
            const nodeGroup = document.createElementNS('http://www.w3.org/2000/svg', 'g');
            nodeGroup.classList.add('node');
            nodeGroup.setAttribute('data-name', node.name);

            if (parentPos) {
                const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
                path.classList.add('connection');
                path.setAttribute('stroke', node.color);

                const midX = (parentPos.x + x) / 2;
                const midY = (parentPos.y + y) / 2;
                const d = `M ${parentPos.x} ${parentPos.y} Q ${midX} ${midY} ${x} ${y}`;
                path.setAttribute('d', d);
                svg.appendChild(path);
            }

            const fontSize = level === 0 ? 20 : level === 1 ? 16 : 14;
            const padding = level === 0 ? 30 : level === 1 ? 20 : 15;
            const textWidth = node.name.length * (fontSize * 0.6);
            const width = textWidth + padding * 2;
            const height = fontSize + padding * 1.5;

            const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
            rect.classList.add('node-rect');
            rect.setAttribute('x', x - width / 2);
            rect.setAttribute('y', y - height / 2);
            rect.setAttribute('width', width);
            rect.setAttribute('height', height);
            rect.setAttribute('rx', level === 0 ? 16 : 10);
            rect.setAttribute('fill', node.color);
            rect.setAttribute('opacity', level === 0 ? 1 : 0.9);

            const text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
            text.classList.add('node-text');
            text.setAttribute('x', x);
            text.setAttribute('y', y);
            text.setAttribute('text-anchor', 'middle');
            text.setAttribute('dominant-baseline', 'middle');
            text.setAttribute('fill', 'white');
            text.setAttribute('font-size', fontSize);
            text.setAttribute('font-weight', level === 0 ? 700 : 500);
            text.textContent = node.name;

            nodeGroup.appendChild(rect);
            nodeGroup.appendChild(text);
            svg.appendChild(nodeGroup);

            nodeGroup.addEventListener('click', () => showInfo(node));

            if (node.children && node.children.length > 0) {
                const isExpanded = expandedNodes.has(node.name) || level === 0;

                if (isExpanded) {
                    const childCount = node.children.length;
                    const radius = level === 0 ? 350 : level === 1 ? 250 : 180;
                    const angleSpread = level === 0 ? 360 : 180;
                    const startAngle = level === 0 ? 0 : angle - angleSpread / 2;

                    node.children.forEach((child, i) => {
                        const childAngle = startAngle + (angleSpread / (childCount - 1 || 1)) * i;
                        const radians = (childAngle * Math.PI) / 180;
                        const childX = x + Math.cos(radians) * radius;
                        const childY = y + Math.sin(radians) * radius;

                        drawNode(child, childX, childY, level + 1, childAngle, { x, y });
                    });
                }

                if (level > 0) {
                    const indicator = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
                    indicator.setAttribute('cx', x + width / 2 - 10);
                    indicator.setAttribute('cy', y);
                    indicator.setAttribute('r', 4);
                    indicator.setAttribute('fill', isExpanded ? '#ffd93d' : 'white');
                    indicator.setAttribute('opacity', 0.8);
                    nodeGroup.appendChild(indicator);
                }
            }
        }

        function showInfo(node) {
            const panel = document.getElementById('info-panel');
            const title = document.getElementById('info-title');
            const content = document.getElementById('info-content');

            if (node.info) {
                title.textContent = node.info.title;
                content.innerHTML = `<p>${node.info.content}</p>`;
                panel.classList.add('visible');
            }
        }

        function closeInfo() {
            document.getElementById('info-panel').classList.remove('visible');
        }

        function resetView() {
            viewBox = { x: 0, y: 0, width: 2000, height: 1500 };
            createMindMap();
        }

        function expandAll() {
            function addAllNodes(node) {
                expandedNodes.add(node.name);
                if (node.children) {
                    node.children.forEach(addAllNodes);
