        // Zoom functionality
        container.addEventListener('wheel', (e) => {
            e.preventDefault();
            const scale = e.deltaY > 0 ? 1.1 : 0.9;
            const mouseX = e.clientX;
            const mouseY = e.clientY;
            const rect = container.getBoundingClientRect();
            const relX = (mouseX - rect.left) / rect.width;
            const relY = (mouseY - rect.top) / rect.height;

            const oldWidth = viewBox.width;
            const oldHeight = viewBox.height;

            viewBox.width *= scale;
            viewBox.height *= scale;

            viewBox.x += (oldWidth - viewBox.width) * relX;
            viewBox.y += (oldHeight - viewBox.height) * relY;

            svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.width} ${viewBox.height}`);
        });

        // Initialize
        expandedNodes.add(data.name);
        createMindMap();
